# ---------------------------------------------------------------------------
# Module-aware locator registry
# ---------------------------------------------------------------------------

def _module_from_path(path: Path) -> str:
    """Derive module name from test file path.

    tests/login/test_login.py  → "login"
    tests/checkout/test_...py  → "checkout"
    """
    parts = path.parts
    try:
        tests_idx = parts.index("tests")
        if tests_idx + 1 < len(parts):
            return parts[tests_idx + 1]
    except ValueError:
        pass
    return path.stem.replace("test_", "")


@pytest.fixture(scope="module")
def locator_registry(request):
    """Module-scoped registry loaded from locators/<module>.json."""
    module = _module_from_path(Path(request.fspath))
    loc_path = Path("locators") / f"{module}.json"
    try:
        from phoenix.locators.registry import LocatorRegistry
        if loc_path.exists():
            return LocatorRegistry.load_page(loc_path)
        return LocatorRegistry.load_all("locators/")
    except ImportError:
        return {}


