# ---------------------------------------------------------------------------
# Rich failure hook — plain-English summary + full technical detail
# ---------------------------------------------------------------------------

@pytest.hookimpl(hookwrapper=True)
def pytest_runtest_makereport(item, call):
    """Capture rich failure detail and attach to pytest-html report.

    For every failed test the report contains (in order):
      1. Plain-English summary (what went wrong, no code)
      2. Full-page screenshot at the moment of failure
      3. Page URL and title
      4. Browser console errors
      5. Full Python traceback (inside a collapsible section)
    """
    outcome = yield
    report = outcome.get_result()

    if report.when != "call" or not report.failed:
        return

    page_fixture = item.funcargs.get("page") or item.funcargs.get("authenticated_page")
    if page_fixture is None:
        return

    extras = getattr(report, "extras", [])
    try:
        import pytest_html  # noqa: F401
        from pytest_html import extras as _extras
    except ImportError:
        _extras = None

    # 1. Screenshot
    screenshots_dir = Path("reports") / "screenshots"
    screenshots_dir.mkdir(parents=True, exist_ok=True)
    safe_name = re.sub(r"[^\w\-]", "_", item.nodeid)
    screenshot_path = screenshots_dir / f"{safe_name}.png"
    screenshot_taken = False
    with suppress(Exception):
        page_fixture.screenshot(path=str(screenshot_path), full_page=True)
        screenshot_taken = True
        report.screenshots = [str(screenshot_path)]

    # 2. Plain-English summary
    try:
        from phoenix.execution.failure_reporter import translate_error
        plain_summary = translate_error(
            report.longrepr.reprcrash.message
            if hasattr(report.longrepr, "reprcrash")
            else Exception(str(report.longreprtext)[:200])
        )
    except Exception:
        plain_summary = ""

    # 3. Page context
    page_url = ""
    page_title = ""
    with suppress(Exception):
        page_url = page_fixture.url
        page_title = page_fixture.title()

    # 4. Console errors
    console_errors: list = []
    with suppress(Exception):
        # collect errors logged via page.on("console", ...) if set up
        console_errors = getattr(page_fixture, "_phoenix_console_errors", [])

    # Build pytest-html extras
    if _extras:
        if plain_summary:
            extras.append(_extras.text(f"⚠ {plain_summary}", name="What happened"))
        if screenshot_taken:
            extras.append(_extras.image(str(screenshot_path), name="Screenshot"))
        if page_url:
            extras.append(_extras.text(f"URL:   {page_url}\nTitle: {page_title}", name="Page context"))
        if console_errors:
            extras.append(_extras.text("\n".join(console_errors), name="Console errors"))
        traceback_text = str(report.longreprtext) if hasattr(report, "longreprtext") else ""
        if traceback_text:
            extras.append(_extras.text(traceback_text, name="Technical detail (traceback)"))
        report.extras = extras


